import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.unmarshalling.Unmarshal
import akka.stream.ActorMaterializer
import spray.json._

import scala.concurrent.{ExecutionContextExecutor, Future}
import scala.util.{Failure, Success}

case class UrlRequest(url: String)
case class ContentResponse(url: String, statusCode: Int, content: String)

trait JsonSupport extends DefaultJsonProtocol {
  implicit val urlRequestFormat = jsonFormat1(UrlRequest)
  implicit val contentResponseFormat = jsonFormat3(ContentResponse)
}

object WebhookProxyService extends App with JsonSupport {
  implicit val system: ActorSystem = ActorSystem("webhook-proxy-service")
  implicit val materializer: ActorMaterializer = ActorMaterializer()
  implicit val executionContext: ExecutionContextExecutor = system.dispatcher

  def fetchContent(url: String): Future[ContentResponse] = {
    val request = HttpRequest(uri = url)
    
    Http().singleRequest(request).flatMap { response =>
      Unmarshal(response.entity).to[String].map { content =>
        ContentResponse(url, response.status.intValue(), content)
      }
    }
  }

  val route =
    path("fetch") {
      post {
        entity(as[String]) { body =>
          val urlRequest = body.parseJson.convertTo[UrlRequest]
          
          onComplete(fetchContent(urlRequest.url)) {
            case Success(response) =>
              complete(StatusCodes.OK, response.toJson.toString())
            case Failure(ex) =>
              complete(StatusCodes.InternalServerError, 
                s"""{"error": "${ex.getMessage}"}""")
          }
        }
      }
    } ~
    path("health") {
      get {
        complete(StatusCodes.OK, "Service is running")
      }
    }

  val bindingFuture = Http().bindAndHandle(route, "0.0.0.0", 8080)

  bindingFuture.onComplete {
    case Success(binding) =>
      println(s"Server online at http://localhost:8080/")
    case Failure(ex) =>
      println(s"Failed to bind HTTP server: ${ex.getMessage}")
      system.terminate()
  }
}